public class Stack {
    private int[] data = new int[10];
    private int top = 0;

    public void push(int val) {
        data[top++] = val;
    }

    public int pop() {
        return data[--top];
    }

    public int peek() {
        return data[top - 1];
    }

    public static void main(String[] args) {
        Stack s = new Stack();
        s.push(10);
        s.push(20);
        s.push(30);
        System.out.println(s.pop());
        System.out.println(s.peek());
        System.out.println(s.pop());
    }
}
